import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

import java.lang.reflect.Field;

public class CSVFormatTest {

    @Test
    void testIsNullHandling_whenNullStringIsNull() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT;
        // Using reflection to set nullString to null
        Field nullStringField = CSVFormat.class.getDeclaredField("nullString");
        nullStringField.setAccessible(true);
        nullStringField.set(format, null);

        boolean result = format.isNullHandling();
        assertFalse(result);
    }

    @Test
    void testIsNullHandling_whenNullStringIsNonNull() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT;
        // Using reflection to set nullString to a non-null value
        Field nullStringField = CSVFormat.class.getDeclaredField("nullString");
        nullStringField.setAccessible(true);
        nullStringField.set(format, "NULL");

        boolean result = format.isNullHandling();
        assertTrue(result);
    }
}
